namespace sv_2b3b9d3d0b0f472da506e7cec1958c1e.Models;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; set; } = Guid.NewGuid();
    public string Title { get; set; } = string.Empty;
    public string Message { get; set; } = string.Empty;
    public Severity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; } = DateTime.UtcNow;
}

using sv_2b3b9d3d0b0f472da506e7cec1958c1e.Models;

namespace sv_2b3b9d3d0b0f472da506e7cec1958c1e.Services;

/// <summary>
/// Scoped per-circuit service that holds notification state and notifies
/// all subscribed components when state changes via an event.
/// </summary>
public class NotificationHub
{
    private readonly List<Notification> _notifications = new();
    private readonly object _lock = new();

    /// <summary>
    /// Raised whenever the notification list changes.
    /// Subscribers must marshal to the UI thread themselves (InvokeAsync).
    /// </summary>
    public event Action? OnChange;

    public IReadOnlyList<Notification> Notifications
    {
        get
        {
            lock (_lock)
            {
                return _notifications.OrderByDescending(n => n.Severity)
                                     .ThenByDescending(n => n.Timestamp)
                                     .ToList()
                                     .AsReadOnly();
            }
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock)
        {
            return _notifications.Count(n => !n.IsRead);
        }
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Add(new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        NotifyStateChanged();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var notification = _notifications.FirstOrDefault(n => n.Id == id);
            if (notification is not null)
                notification.IsRead = true;
        }
        NotifyStateChanged();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }
        NotifyStateChanged();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

using sv_2b3b9d3d0b0f472da506e7cec1958c1e.Models;

namespace sv_2b3b9d3d0b0f472da506e7cec1958c1e.Services;

/// <summary>
/// Scoped service that simulates server-push events by adding a random
/// notification every 15 seconds. Started/stopped by the dashboard page.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private Timer? _timer;
    private static readonly Random _random = new();

    private static readonly string[] Titles =
    [
        "Deployment Complete",
        "CPU Spike Detected",
        "New User Signup",
        "Disk Space Low",
        "Build Failed",
        "Security Alert",
        "Backup Finished",
        "Service Degraded"
    ];

    private static readonly string[] Messages =
    [
        "A scheduled task has completed successfully.",
        "Resource utilization exceeded threshold for 5 minutes.",
        "A new user registered via OAuth.",
        "Available disk space is below 10%.",
        "Pipeline #4521 failed at the test stage.",
        "Unusual login activity detected from new IP.",
        "Nightly backup completed without errors.",
        "Response times are elevated in the EU region."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        _timer ??= new Timer(AddRandomNotification, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    public void Stop()
    {
        _timer?.Dispose();
        _timer = null;
    }

    private void AddRandomNotification(object? state)
    {
        var index = _random.Next(Titles.Length);
        var severity = (Severity)_random.Next(3);
        _hub.AddNotification(Titles[index], Messages[index], severity);
    }

    public void Dispose()
    {
        Stop();
    }
}

