@using sv_2b3b9d3d0b0f472da506e7cec1958c1e.Services
@implements IDisposable
@inject NotificationHub Hub
@rendermode InteractiveServer

<div class="notification-bell position-relative d-inline-block px-3 py-2" @onclick="ToggleDropdown" style="cursor: pointer;">
    <span class="bi bi-bell-fill" aria-hidden="true" style="font-size: 1.2rem;">🔔</span>
    @if (_unreadCount > 0)
    {
        <span class="badge bg-danger rounded-pill position-absolute top-0 start-100 translate-middle">
            @_unreadCount
        </span>
    }
</div>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += HandleStateChanged;
    }

    private void HandleStateChanged()
    {
        // Marshal to the UI synchronization context
        InvokeAsync(() =>
        {
            _unreadCount = Hub.GetUnreadCount();
            StateHasChanged();
        });
    }

    public void Dispose()
    {
        Hub.OnChange -= HandleStateChanged;
    }
}

