    {
        LoadState();
        Hub.OnChange += HandleStateChanged;
    }

    private void LoadState()
    {
        _notifications = Hub.Notifications;
        _unreadCount = Hub.GetUnreadCount();
    }

    private void MarkRead(Guid id) => Hub.MarkAsRead(id);

