@page "/dashboard"
@using sv_2b3b9d3d0b0f472da506e7cec1958c1e.Services
@implements IDisposable
@inject SimulatorService Simulator
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h1>Dashboard</h1>

<p class="text-muted">A random notification is generated every 15 seconds to simulate server-push events.</p>

<div class="row mt-4">
    <div class="col-md-8">
        <NotificationSummaryPanel />
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        Simulator.Start();
    }

    public void Dispose()
    {
        Simulator.Stop();
    }
}

